code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();

        while (t--> 0) {
            int n = sc.nextInt();

            int[] a = new int[n];
            int[] b = new int[n];
            for (int i = 0; i < n; i++) {
                a[i] = sc.nextInt();
            }
            for (int i = 0; i < n; i++) {
                b[i] = sc.nextInt();
            }

            List < int[] > intervals = new ArrayList < > ();
            for (int i = 0; i < n; i++) {
                intervals.add(new int[] {
                    a[i], b[i]
                });
            }

            intervals.sort(Comparator.comparingInt(o -> o[0]));

            int answer = 1;
            for (int i = 0; i < n; i++) {
                int start = intervals.get(i)[0];
                int end = intervals.get(i)[1];

                for (int j = start; j < end; j++) {
                    int count = 0;
                    for (int k = 0; k < n; k++) {
                        int intervalStart = intervals.get(k)[0];
                        int intervalEnd = intervals.get(k)[1];
                        if (intervalStart <= j && intervalEnd > j) {
                            count++;
                        }
                    }
                    answer = Math.max(answer, count);
                }
            }

            System.out.println(answer);
        }

        sc.close();
    }
}

